"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { type ChatStatus, DefaultChatTransport, type UIMessage } from "ai";
import { useState } from "react";

interface CreateDemoChatOptions {
  api: string;
}

interface UseDemoChatWithApiOptions extends CreateDemoChatOptions {
  createChat?: never;
}

interface UseDemoChatWithFactoryOptions<TMessage extends UIMessage> {
  api?: never;
  createChat: () => Chat<TMessage>;
}

type UseDemoChatOptions<TMessage extends UIMessage> =
  | UseDemoChatWithApiOptions
  | UseDemoChatWithFactoryOptions<TMessage>;

export function createDemoChat<TMessage extends UIMessage = UIMessage>({
  api,
}: CreateDemoChatOptions) {
  return new Chat<TMessage>({
    transport: new DefaultChatTransport({
      api,
    }),
  });
}

export function isDemoChatBusyStatus(status: ChatStatus) {
  return status === "submitted" || status === "streaming";
}

export function useDemoChat<TMessage extends UIMessage = UIMessage>(
  options: UseDemoChatOptions<TMessage>
) {
  const [chat] = useState(() => {
    if (options.createChat) {
      return options.createChat();
    }

    return createDemoChat<TMessage>({ api: options.api });
  });
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy = isDemoChatBusyStatus(controller.status);

  return {
    ...controller,
    chat,
    hasMessages,
    isBusy,
  };
}

import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import type { ReactNode } from "react";

import { DemoBreadcrumb } from "@/components/demo-breadcrumb";

type DemoWorkspaceHeaderFrame = "header" | "card";

interface DemoWorkspaceShellProps {
  badges?: readonly ReactNode[];
  breadcrumbClassName?: string;
  breadcrumbTitle?: string;
  children: ReactNode;
  contentClassName?: string;
  headerClassName?: string;
  headerFrame?: DemoWorkspaceHeaderFrame;
  maxWidthClassName?: string;
  summary: ReactNode;
  summaryClassName?: string;
  title: string;
  titleClassName?: string;
  workspaceClassName?: string | null;
}

const defaultHeaderClassName =
  "grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end";

const cardHeaderClassName =
  "grid gap-4 bg-background px-4 py-5 text-base text-foreground leading-normal md:grid-cols-[minmax(0,1fr)_auto] md:items-end";

export function DemoWorkspaceShell({
  badges = [],
  breadcrumbClassName,
  breadcrumbTitle,
  children,
  contentClassName,
  headerClassName,
  headerFrame = "header",
  maxWidthClassName = "max-w-7xl",
  summary,
  summaryClassName = "max-w-3xl",
  title,
  titleClassName = "max-w-3xl",
  workspaceClassName = "lg:h-svh",
}: DemoWorkspaceShellProps) {
  const headerContent = (
    <>
      <div className="space-y-2">
        <DemoBreadcrumb
          className={breadcrumbClassName}
          title={breadcrumbTitle ?? title}
        />
        <h1
          className={cn("font-medium text-2xl tracking-tight", titleClassName)}
        >
          {title}
        </h1>
        <p
          className={cn(
            "text-muted-foreground text-sm/relaxed",
            summaryClassName
          )}
        >
          {summary}
        </p>
      </div>

      {badges.length > 0 ? (
        <div className="flex flex-wrap items-center gap-2">
          {badges.map((badge, index) => (
            <Badge key={String(index)} variant="outline">
              {badge}
            </Badge>
          ))}
        </div>
      ) : null}
    </>
  );

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div
        className={cn(
          "mx-auto flex w-full flex-col gap-6 px-4 py-6 md:px-6",
          maxWidthClassName,
          contentClassName
        )}
      >
        {headerFrame === "card" ? (
          <Card className={cn(cardHeaderClassName, headerClassName)}>
            {headerContent}
          </Card>
        ) : (
          <header className={cn(defaultHeaderClassName, headerClassName)}>
            {headerContent}
          </header>
        )}

        {workspaceClassName ? (
          <div className={workspaceClassName}>{children}</div>
        ) : (
          children
        )}
      </div>
    </main>
  );
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import type {
  OpenAiAgentsSdkDemoMessage,
  OpenAiAgentsSdkDemoMessageMetadata,
} from "@/lib/openai-agents-sdk-demo/message-metadata";
import type { OpenAiAgentsSdkDemoAiSdkExtensionProfile } from "@/lib/openai-agents-sdk-demo/server/extensions";
import type { OpenAiAgentsSdkDemoGuideCoverage } from "@/lib/openai-agents-sdk-demo/server/guide-coverage";
import type { OpenAiAgentsSdkDemoTraceProfile } from "@/lib/openai-agents-sdk-demo/server/tracing";
import { hasOpenAiAgentsSdkDemoVisibleContent } from "./openai-agents-sdk-demo-session";

type MetadataKey = keyof OpenAiAgentsSdkDemoMessageMetadata;

export interface OpenAiAgentsSdkDemoRuntimeInspectorInput {
  aiSdkExtensionProfile: OpenAiAgentsSdkDemoAiSdkExtensionProfile;
  guideCoverage: OpenAiAgentsSdkDemoGuideCoverage[];
  hasUsedVoiceGuide: boolean;
  messages: OpenAiAgentsSdkDemoMessage[];
  traceProfile: OpenAiAgentsSdkDemoTraceProfile;
}

export interface OpenAiAgentsSdkDemoRuntimeInspector {
  aiSdkModelAdapterStatus: string;
  aiSdkUiBridgeStatus: string;
  guideCoverageWithCurrentRun: OpenAiAgentsSdkDemoGuideCoverage[];
  hasPendingApproval: boolean;
  lastAiSdkExtensionSummary?: OpenAiAgentsSdkDemoMessageMetadata["aiSdkExtensionSummary"];
  lastApprovalSummary?: OpenAiAgentsSdkDemoMessageMetadata["approvalSummary"];
  lastContextSummary?: OpenAiAgentsSdkDemoMessageMetadata["contextSummary"];
  lastHandoffSummary?: OpenAiAgentsSdkDemoMessageMetadata["handoffSummary"];
  lastMcpSummary?: OpenAiAgentsSdkDemoMessageMetadata["mcpSummary"];
  lastResponseId?: string;
  lastResultSummary?: OpenAiAgentsSdkDemoMessageMetadata["resultSummary"];
  lastSandboxSummary?: OpenAiAgentsSdkDemoMessageMetadata["sandboxSummary"];
  lastSessionSummary?: OpenAiAgentsSdkDemoMessageMetadata["sessionSummary"];
  lastStreamSummary?: OpenAiAgentsSdkDemoMessageMetadata["streamSummary"];
  lastTraceSummary?: OpenAiAgentsSdkDemoMessageMetadata["traceSummary"];
  traceIncludesSensitiveData: boolean;
  usedGuardrailNames: Set<string>;
  usedGuideIds: Set<string>;
  usedToolNames: Set<string>;
}

function getLatestAssistantMessage(messages: OpenAiAgentsSdkDemoMessage[]) {
  return [...messages]
    .reverse()
    .find((message) => message.role === "assistant");
}

function getLatestAssistantMetadata<K extends MetadataKey>(
  messages: OpenAiAgentsSdkDemoMessage[],
  key: K
) {
  return [...messages]
    .reverse()
    .find((message) => message.role === "assistant" && message.metadata?.[key])
    ?.metadata?.[key];
}

export function buildOpenAiAgentsSdkDemoRuntimeInspector({
  aiSdkExtensionProfile,
  guideCoverage,
  hasUsedVoiceGuide,
  messages,
  traceProfile,
}: OpenAiAgentsSdkDemoRuntimeInspectorInput): OpenAiAgentsSdkDemoRuntimeInspector {
  const hasAssistantOutput = messages.some(
    (message) =>
      message.role === "assistant" &&
      hasOpenAiAgentsSdkDemoVisibleContent(message)
  );
  const usedGuideIds = new Set(
    messages.flatMap((message) => message.metadata?.usedGuideIds ?? [])
  );
  const usedToolNames = new Set(
    messages.flatMap((message) => message.metadata?.usedToolNames ?? [])
  );
  const usedGuardrailNames = new Set(
    messages.flatMap((message) => message.metadata?.usedGuardrailNames ?? [])
  );
  const lastAiSdkExtensionSummary = getLatestAssistantMetadata(
    messages,
    "aiSdkExtensionSummary"
  );
  const lastApprovalSummary = getLatestAssistantMetadata(
    messages,
    "approvalSummary"
  );
  const lastTraceSummary = getLatestAssistantMetadata(messages, "traceSummary");
  const guideCoverageWithCurrentRun = guideCoverage.map((item) => {
    const wasUsedThisRun =
      ((item.id === "agents" || item.id === "models") && hasAssistantOutput) ||
      usedGuideIds.has(item.id) ||
      (item.id === "voice-agents" && hasUsedVoiceGuide);

    if (!wasUsedThisRun) {
      return item;
    }

    return {
      ...item,
      currentRunStatus: "used-this-run" as const,
    };
  });

  return {
    aiSdkModelAdapterStatus:
      lastAiSdkExtensionSummary?.modelAdapterStatus ??
      aiSdkExtensionProfile.modelAdapter.status,
    aiSdkUiBridgeStatus:
      lastAiSdkExtensionSummary?.uiBridgeStatus ??
      aiSdkExtensionProfile.uiBridge.status,
    guideCoverageWithCurrentRun,
    hasPendingApproval: Boolean(lastApprovalSummary?.hasPendingApprovals),
    lastAiSdkExtensionSummary,
    lastApprovalSummary,
    lastContextSummary: getLatestAssistantMetadata(messages, "contextSummary"),
    lastHandoffSummary: getLatestAssistantMetadata(messages, "handoffSummary"),
    lastMcpSummary: getLatestAssistantMetadata(messages, "mcpSummary"),
    lastResponseId:
      getLatestAssistantMessage(messages)?.metadata?.lastResponseId,
    lastResultSummary: getLatestAssistantMetadata(messages, "resultSummary"),
    lastSandboxSummary: getLatestAssistantMetadata(messages, "sandboxSummary"),
    lastSessionSummary: getLatestAssistantMetadata(messages, "sessionSummary"),
    lastStreamSummary: getLatestAssistantMetadata(messages, "streamSummary"),
    lastTraceSummary,
    traceIncludesSensitiveData:
      lastTraceSummary?.traceIncludeSensitiveData ??
      traceProfile.traceIncludeSensitiveData,
    usedGuardrailNames,
    usedGuideIds,
    usedToolNames,
  };
}

