function OpenAiAgentsSdkDemoToolApproval({
  onApprovalResponse,
  part,
}: {
  onApprovalResponse: ChatAddToolApproveResponseFunction;
  part: ToolPart;
}) {
  if (!("approval" in part && part.approval)) {
    return null;
