function createOpenAiAgentsSdkDemoUiMessageStream(
  eventSource: Parameters<typeof createAiSdkUiMessageStream>[0],
  agentStream: DemoAgentStream
) {
  const baseStream = createAiSdkUiMessageStream(eventSource);

  return new ReadableStream<UIMessageChunk>({
    async start(controller) {
      const reader = baseStream.getReader();
      let finishChunk: UIMessageChunk | null = null;

      try {
        while (true) {
          const { done, value } = await reader.read();

          if (done) {
            break;
          }

          if (value.type === "finish") {
            finishChunk = value;
            continue;
          }

          controller.enqueue(value);
        }

        await agentStream.completed;

        for (const chunk of getOpenAiAgentsSdkDemoArtifactChunks({
          newItems: agentStream.newItems,
          rawResponses: agentStream.rawResponses,
        })) {
          controller.enqueue(chunk);
        }

        controller.enqueue(
          finishChunk ?? {
            finishReason: "stop",
            type: "finish",
          }
        );
        controller.close();
      } catch (error) {
        controller.error(error);
      } finally {
        reader.releaseLock();
      }
    },
    async cancel(reason) {
      await baseStream.cancel(reason);
    },
  });
}

function mergeOpenAiAgentsSdkDemoMessageMetadata(
  ...metadataEntries: Array<OpenAiAgentsSdkDemoMessageMetadata | undefined>
): OpenAiAgentsSdkDemoMessageMetadata | undefined {
  const aiSdkExtensionSummary = metadataEntries
    .map((item) => item?.aiSdkExtensionSummary)
    .find((value) => value);
  const approvalSummary = metadataEntries
    .map((item) => item?.approvalSummary)
    .find((value) => value);
  const contextSummary = metadataEntries
    .map((item) => item?.contextSummary)
    .find((value) => value);
  const handoffSummary = metadataEntries
    .map((item) => item?.handoffSummary)
    .find((value) => value);
  const lastResponseId = metadataEntries
    .map((item) => item?.lastResponseId)
    .filter((value): value is string => Boolean(value))
    .at(-1);
  const mcpSummary = metadataEntries
    .map((item) => item?.mcpSummary)
    .find((value) => value);
  const resultSummary = metadataEntries
    .map((item) => item?.resultSummary)
    .find((value) => value);
  const sandboxSummary = metadataEntries
    .map((item) => item?.sandboxSummary)
    .find((value) => value);
  const sessionSummary = metadataEntries
    .map((item) => item?.sessionSummary)
    .find((value) => value);
  const streamSummary = metadataEntries
    .map((item) => item?.streamSummary)
    .find((value) => value);
  const traceSummary = metadataEntries
    .map((item) => item?.traceSummary)
    .find((value) => value);
  const usedGuideIds = Array.from(
    new Set(metadataEntries.flatMap((item) => item?.usedGuideIds ?? []))
  );
  const usedGuardrailNames = Array.from(
    new Set(metadataEntries.flatMap((item) => item?.usedGuardrailNames ?? []))
  );
  const usedToolNames = Array.from(
    new Set(metadataEntries.flatMap((item) => item?.usedToolNames ?? []))
  );

  if (
    !(
      aiSdkExtensionSummary ||
      approvalSummary ||
      contextSummary ||
      handoffSummary ||
      lastResponseId ||
      mcpSummary ||
      resultSummary ||
      sandboxSummary ||
      sessionSummary ||
      streamSummary ||
      traceSummary
    ) &&
    usedGuideIds.length === 0 &&
    usedGuardrailNames.length === 0 &&
    usedToolNames.length === 0
  ) {
    return;
  }

  return {
    ...(aiSdkExtensionSummary ? { aiSdkExtensionSummary } : {}),
    ...(approvalSummary ? { approvalSummary } : {}),
    ...(contextSummary ? { contextSummary } : {}),
    ...(handoffSummary ? { handoffSummary } : {}),
    ...(lastResponseId ? { lastResponseId } : {}),
    ...(mcpSummary ? { mcpSummary } : {}),
    ...(resultSummary ? { resultSummary } : {}),
    ...(sandboxSummary ? { sandboxSummary } : {}),
    ...(sessionSummary ? { sessionSummary } : {}),
    ...(streamSummary ? { streamSummary } : {}),
    ...(traceSummary ? { traceSummary } : {}),
    ...(usedGuideIds.length > 0 ? { usedGuideIds } : {}),
    ...(usedGuardrailNames.length > 0 ? { usedGuardrailNames } : {}),
    ...(usedToolNames.length > 0 ? { usedToolNames } : {}),
  };
}

export async function streamOpenAiAgentsSdkDemo(
  messages: UIMessage[],
  env: DemoEnv = process.env,
  options?: {
    origin?: string;
    signal?: AbortSignal;
  }
) {
  configureOpenAiAgentsSdkDemoGatewayClient(env);
  const modelProfile = getOpenAiAgentsSdkDemoModelProfile(env);
  const { agent, mcpServers } = await createDemoAgent(
    env,
    options?.origin ?? "http://localhost:3000"
  );
  let shouldCloseMcpServersImmediately = true;
  const runProfile = getOpenAiAgentsSdkDemoRunProfile(env);
  const session = await getOpenAiAgentsSdkDemoSession(messages);
  const demoContext = await createOpenAiAgentsSdkDemoContext({
    messages,
    session,
  });
  const traceRunConfig = createOpenAiAgentsSdkDemoTraceRunConfig({
    env,
    sessionId: demoContext.sessionId,
    workflowName: runProfile.workflowName,
  });
  const sandboxRunConfig = getOpenAiAgentsSdkDemoSandboxRunConfig({
    sessionId: demoContext.sessionId,
  });
  const approvalResume = await getOpenAiAgentsSdkDemoApprovalResumeState(
    messages,
    agent
  );

  assertOpenAiAgentsSdkDemoNoPendingApproval(messages);

  let agentStream: DemoAgentStream;

  if (approvalResume) {
    agentStream = (await run(agent, approvalResume.state, {
      ...(options?.signal ? { signal: options.signal } : {}),
      maxTurns: runProfile.maxTurns,
      ...sandboxRunConfig,
      session,
      stream: true as const,
    })) as DemoAgentStream;
  } else {
    const runRequest = getOpenAiAgentsSdkDemoRunRequest(
      {
        messages,
        signal: options?.signal,
      },
      env
    );

    agentStream = (await run(agent, runRequest.input, {
      context: demoContext,
      ...runRequest.options,
      ...sandboxRunConfig,
      session,
      ...traceRunConfig.options,
    })) as DemoAgentStream;
  }
  const streamSummaryCollector =
    createOpenAiAgentsSdkDemoStreamSummaryCollector();
  const observedEventStream = observeOpenAiAgentsSdkDemoStreamEvents(
    agentStream,
    (event) => {
      streamSummaryCollector.observe(event);
    }
  );
  const uiMessageStream = createOpenAiAgentsSdkDemoUiMessageStream(
    observedEventStream,
    agentStream
  );

  try {
    const response = createUIMessageStreamResponse({
      stream: createUIMessageStream({
        execute({ writer }) {
          writer.merge(uiMessageStream);

          return agentStream.completed
            .then(() => {
              const sessionMetadataPromise =
                getOpenAiAgentsSdkDemoSessionUsageMetadata(session);

              return sessionMetadataPromise.then((sessionMetadata) => {
                recordOpenAiAgentsSdkDemoSandboxSessionState({
                  sessionId: demoContext.sessionId,
                  state: agentStream.state,
                });

                const metadata = mergeOpenAiAgentsSdkDemoMessageMetadata(
                  getOpenAiAgentsSdkDemoRunningUsageMetadata(
                    agentStream.lastResponseId
                  ),
                  getOpenAiAgentsSdkDemoApprovalUsageMetadata({
                    interruptions: agentStream.interruptions ?? [],
                    responses: approvalResume?.responses,
                    state: agentStream.state,
                  }),
                  streamSummaryCollector.toMetadata(),
                  getOpenAiAgentsSdkDemoHandoffUsageMetadata({
                    activeAgentName: agentStream.lastAgent?.name,
                    newItems: agentStream.newItems ?? [],
                  }),
                  getOpenAiAgentsSdkDemoResultUsageMetadata({
                    activeAgentName: agentStream.activeAgent?.name,
                    finalOutput: agentStream.finalOutput,
                    hasResumableState: Boolean(agentStream.state),
                    historyLength: agentStream.history?.length ?? 0,
                    interruptionCount: agentStream.interruptions?.length ?? 0,
                    lastAgentName: agentStream.lastAgent?.name,
                    newItemsCount: agentStream.newItems?.length ?? 0,
                    outputCount: agentStream.output?.length ?? 0,
                    rawResponseCount: agentStream.rawResponses?.length ?? 0,
                    usage: agentStream.state?.usage,
                  }),
                  getOpenAiAgentsSdkDemoContextUsageMetadata(demoContext),
                  getOpenAiAgentsSdkDemoMcpUsageMetadata({
                    mcpServers,
                    newItems: agentStream.newItems ?? [],
                  }),
                  getOpenAiAgentsSdkDemoSandboxUsageMetadata({
                    newItems: agentStream.newItems ?? [],
                    sessionId: demoContext.sessionId,
                    state: agentStream.state,
                  }),
                  getOpenAiAgentsSdkDemoAiSdkExtensionUsageMetadata(),
                  sessionMetadata,
                  approvalResume
                    ? getOpenAiAgentsSdkDemoLatestTraceUsageMetadata(messages)
                    : getOpenAiAgentsSdkDemoTraceUsageMetadata(
                        traceRunConfig.summary
                      ),
                  getOpenAiAgentsSdkDemoRunUsageMetadata(
                    agentStream.newItems ?? []
                  ),
                  getOpenAiAgentsSdkDemoGuardrailUsageMetadata({
                    inputGuardrailResults: (agentStream.inputGuardrailResults ??
                      []) as Parameters<
                      typeof getOpenAiAgentsSdkDemoGuardrailUsageMetadata
                    >[0]["inputGuardrailResults"],
                    outputGuardrailResults:
                      (agentStream.outputGuardrailResults ?? []) as Parameters<
                        typeof getOpenAiAgentsSdkDemoGuardrailUsageMetadata
                      >[0]["outputGuardrailResults"],
                  })
                );

                if (!metadata) {
                  return;
                }

                writer.write({
                  messageMetadata: metadata,
                  type: "message-metadata",
                });
              });
            })
            .finally(() => mcpServers.close());
        },
        onError(error) {
          const approvalMessage =
            getOpenAiAgentsSdkDemoApprovalErrorMessage(error);

          if (approvalMessage) {
            return approvalMessage;
          }

          const guardrailMessage =
            getOpenAiAgentsSdkDemoGuardrailErrorMessage(error);

          if (guardrailMessage) {
            return guardrailMessage;
          }

          if (
            error instanceof Error &&
            error.message === "terminated" &&
            isOpenAiAgentsSdkDemoImageGenerationProviderBlocked(modelProfile) &&
            isLikelyImageGenerationPrompt(messages)
          ) {
            return "The current AI Gateway Responses path registered imageGenerationTool(), but the upstream stream terminated before this demo received a renderable image artifact. In this provider configuration, image generation is blocked.";
          }

          const providerErrorMessage =
            getOpenAiAgentsSdkDemoProviderErrorMessage(error);

          if (providerErrorMessage) {
            return providerErrorMessage;
          }

          return error instanceof Error
            ? error.message
            : "The agent stream failed.";
        },
      }),
    });

    shouldCloseMcpServersImmediately = false;
    return response;
  } finally {
    if (shouldCloseMcpServersImmediately) {
      await mcpServers.close();
    }
  }
}

import type { MemorySession, RunContext } from "@openai/agents";
import type { UIMessage } from "ai";
import { z } from "zod";

import type { OpenAiAgentsSdkDemoMessageMetadata } from "../message-metadata";

const defaultResearchTarget = "Tesla";
const maxPromptPreviewLength = 120;

export const openAiAgentsSdkDemoContextSummarySchema = z.object({
  defaultResearchTarget: z.literal(defaultResearchTarget),
  latestUserPromptPreview: z.string(),
  localContextKind: z.literal("RunContext"),
  researchMode: z.enum(["company-analysis", "general"]),
  sessionId: z.string(),
  sessionKind: z.literal("MemorySession"),
});

export interface OpenAiAgentsSdkDemoContextProfile {
  localContextPrimitive: "RunContext";
  passesContextInto: Array<
    "agent.asTool toolInput" | "dynamic instructions" | "guardrails" | "tool()"
  >;
  sessionBinding: "session-id";
  suggestedDefaultTarget: "Tesla";
}

export interface OpenAiAgentsSdkDemoContext {
  defaultResearchTarget: "Tesla";
  latestUserPrompt: string;
  latestUserPromptPreview: string;
  researchMode: "company-analysis" | "general";
  sessionId: string;
  sessionKind: "MemorySession";
}

function getLatestUserPrompt(messages: UIMessage[]) {
  return (
    [...messages]
      .reverse()
      .find((message) => message.role === "user")
      ?.parts.filter((part) => part.type === "text")
      .map((part) => part.text)
      .join("\n")
      .trim() ?? ""
  );
}

function getPromptPreview(text: string) {
  if (text.length <= maxPromptPreviewLength) {
    return text;
  }

  return `${text.slice(0, maxPromptPreviewLength - 1)}...`;
}

function inferResearchMode(
  latestUserPrompt: string
): OpenAiAgentsSdkDemoContext["researchMode"] {
  if (
    /(company|stock|equity|earnings|valuation|financial|10-k|10q|tesla|分析|财务|投研|公司|研究|估值)/i.test(
      latestUserPrompt
    )
  ) {
    return "company-analysis";
  }

  return "general";
}

export async function createOpenAiAgentsSdkDemoContext({
  messages,
  session,
}: {
  messages: UIMessage[];
  session: Pick<MemorySession, "getSessionId">;
}): Promise<OpenAiAgentsSdkDemoContext> {
  const latestUserPrompt = getLatestUserPrompt(messages);

  return {
    defaultResearchTarget,
    latestUserPrompt,
    latestUserPromptPreview: getPromptPreview(latestUserPrompt),
    researchMode: inferResearchMode(latestUserPrompt),
    sessionId: await session.getSessionId(),
    sessionKind: "MemorySession",
  };
}

export function getOpenAiAgentsSdkDemoContextProfile(): OpenAiAgentsSdkDemoContextProfile {
  return {
    localContextPrimitive: "RunContext",
    passesContextInto: [
      "dynamic instructions",
      "tool()",
      "guardrails",
      "agent.asTool toolInput",
    ],
    sessionBinding: "session-id",
    suggestedDefaultTarget: "Tesla",
  };
}

export function getOpenAiAgentsSdkDemoContextInstructions(
  runContext: RunContext<OpenAiAgentsSdkDemoContext>,
  options: {
    isImageGenerationProviderBlocked: boolean;
  }
) {
  const context = runContext.context;
  const instructionLines = [
    `Current demo run mode: ${context.researchMode}.`,
    context.researchMode === "company-analysis"
      ? `If the user requests company research without naming a company, default to ${context.defaultResearchTarget}.`
      : "Keep the answer general unless the user explicitly asks for company research.",
  ];

  if (options.isImageGenerationProviderBlocked) {
    instructionLines.push(
      "The current AI Gateway Responses path cannot return a renderable image_generation artifact to this chat surface. For image-generation requests, explain that the official hosted tool is currently provider-blocked in this demo instead of claiming success."
    );
  }

  return instructionLines.join(" ");
}

export function getOpenAiAgentsSdkDemoToolContextNote(
  runContext?: RunContext<OpenAiAgentsSdkDemoContext>
) {
  const context = runContext?.context;

  if (!context) {
    return null;
  }

  return `Run context: ${context.researchMode}; default research target when unspecified: ${context.defaultResearchTarget}.`;
}

export function getOpenAiAgentsSdkDemoContextUsageMetadata(
  context: OpenAiAgentsSdkDemoContext
) {
  return {
    contextSummary: {
      defaultResearchTarget: context.defaultResearchTarget,
      latestUserPromptPreview: context.latestUserPromptPreview,
      localContextKind: "RunContext",
      researchMode: context.researchMode,
      sessionId: context.sessionId,
      sessionKind: context.sessionKind,
    },
    usedGuideIds: ["context"],
  } satisfies OpenAiAgentsSdkDemoMessageMetadata;
}

import { existsSync } from "node:fs";
import { readFile } from "node:fs/promises";
import path from "node:path";
// biome-ignore lint/correctness/noUnresolvedImports: the MCP SDK wildcard export requires the .js subpath at runtime.
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
// biome-ignore lint/correctness/noUnresolvedImports: the MCP SDK wildcard export requires the .js subpath at runtime.
import { WebStandardStreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/webStandardStreamableHttp.js";
import { z } from "zod";

import {
  OPENAI_AGENTS_SDK_DEMO_MCP_SERVER_NAME,
  openAiAgentsSdkDemoMcpToolNames,
} from "./mcp";

const demoDocIds = ["feature-readme", "frontend-doc"] as const;

function firstExistingPath(paths: readonly string[], label: string) {
  const resolvedPath = paths.find((candidate) => existsSync(candidate));

  if (!resolvedPath) {
    throw new Error(
      `Could not resolve the OpenAI Agents SDK demo ${label} document from cwd ${process.cwd()}.`
    );
  }

  return resolvedPath;
}

function getDemoDocumentPaths() {
  return {
    featureReadme: firstExistingPath(
      [
        path.join(process.cwd(), "lib/openai-agents-sdk-demo/README.md"),
        path.join(process.cwd(), "src/lib/openai-agents-sdk-demo/README.md"),
      ],
      "README"
    ),
    frontendDoc: firstExistingPath(
      [
        path.join(process.cwd(), "docs/frontend/openai-agents-sdk-demo.md"),
        path.join(process.cwd(), "src/docs/frontend/openai-agents-sdk-demo.md"),
      ],
      "frontend docs"
    ),
  };
}

function jsonText(value: unknown) {
  return {
    content: [
      {
        text: JSON.stringify(value, null, 2),
        type: "text" as const,
      },
    ],
  };
}

async function getDemoDocSources() {
  const paths = getDemoDocumentPaths();

  return [
    {
      id: "feature-readme" as const,
      label: "lib/openai-agents-sdk-demo/README.md",
      text: await readFile(paths.featureReadme, "utf8"),
    },
    {
      id: "frontend-doc" as const,
      label: "docs/frontend/openai-agents-sdk-demo.md",
      text: await readFile(paths.frontendDoc, "utf8"),
    },
  ];
}

async function readDemoDoc(document: (typeof demoDocIds)[number]) {
  const sources = await getDemoDocSources();
  const source = sources.find((item) => item.id === document);

  if (!source) {
    throw new Error(`Unknown demo document: ${document}`);
  }

  return {
    document: source.id,
    label: source.label,
    text: source.text,
  };
}

async function searchDemoDocs({
  limit = 6,
  query,
}: {
  limit?: number;
  query: string;
}) {
  const normalizedQuery = query.trim().toLowerCase();

  if (!normalizedQuery) {
    return [];
  }

  const sources = await getDemoDocSources();
  const matches: Array<{
    document: string;
    line: number;
    text: string;
  }> = [];

  for (const source of sources) {
    const lines = source.text.split("\n");

    for (let index = 0; index < lines.length; index += 1) {
      const lineText = lines[index]?.trim() ?? "";

      if (!lineText.toLowerCase().includes(normalizedQuery)) {
        continue;
      }

      matches.push({
        document: source.label,
        line: index + 1,
        text: lineText,
      });

      if (matches.length >= limit) {
        return matches;
      }
    }
  }

  return matches;
}

export function createOpenAiAgentsSdkDemoMcpServer() {
  const server = new McpServer(
    {
      name: OPENAI_AGENTS_SDK_DEMO_MCP_SERVER_NAME,
      title: "OpenAI Agents SDK Demo Docs",
      version: "0.1.0",
    },
    {
      instructions:
        "Use these tools when the user asks about this demo's README, durable frontend doc, setup contract, or official guide coverage notes.",
    }
  );

  server.registerTool(
    openAiAgentsSdkDemoMcpToolNames[0],
    {
      description:
        "Read one durable document for the OpenAI Agents SDK demo feature slice.",
      inputSchema: {
        document: z.enum(demoDocIds),
      },
    },
    async ({ document }) => jsonText(await readDemoDoc(document))
  );

  server.registerTool(
    openAiAgentsSdkDemoMcpToolNames[1],
    {
      description:
        "Search the OpenAI Agents SDK demo README and durable frontend doc for line-level matches.",
      inputSchema: {
        limit: z.number().int().min(1).max(20).optional(),
        query: z.string().min(1),
      },
    },
    async ({ limit, query }) => jsonText(await searchDemoDocs({ limit, query }))
  );

  return server;
}

export async function handleOpenAiAgentsSdkDemoMcpRequest(request: Request) {
  const server = createOpenAiAgentsSdkDemoMcpServer();
  const transport = new WebStandardStreamableHTTPServerTransport({
    enableJsonResponse: true,
    sessionIdGenerator: undefined,
  });

  await server.connect(transport);

  try {
    return await transport.handleRequest(request);
  } finally {
    await server.close();
  }
}

