  sessionStore.clear();
}

import type { ModelResponse, RunItem } from "@openai/agents";
import type { UIMessageChunk } from "ai";

const defaultGeneratedImageMediaType = "image/png";

interface ImageGenerationArtifactSource {
  id?: string;
  name?: string;
  output?: string;
  result?: string | null;
  status?: string;
  type?: string;
}

interface ImageGenerationRunArtifact {
  id: string;
  result: string;
}

function getImageGenerationArtifact({
  output,
  rawItem,
}: {
  output?: string;
  rawItem: ImageGenerationArtifactSource | undefined;
}): ImageGenerationRunArtifact | null {
  if (!rawItem) {
    return null;
  }

  if (
    rawItem.type === "image_generation_call" &&
    rawItem.status === "completed" &&
    typeof rawItem.result === "string" &&
    rawItem.result.length > 0
  ) {
    return {
      id: rawItem.id ?? rawItem.result,
      result: rawItem.result,
    };
  }

  const hostedOutput =
    typeof output === "string"
      ? output
      : typeof rawItem.output === "string"
        ? rawItem.output
        : null;

  if (
    rawItem.type === "hosted_tool_call" &&
    rawItem.name === "image_generation_call" &&
    rawItem.status === "completed" &&
    hostedOutput &&
    hostedOutput.length > 0
  ) {
    return {
      id: rawItem.id ?? hostedOutput,
      result: hostedOutput,
    };
  }

  return null;
}

function appendArtifactChunk(
  chunks: UIMessageChunk[],
  emittedImageIds: Set<string>,
  artifact: ImageGenerationRunArtifact | null
) {
  if (!artifact || emittedImageIds.has(artifact.id)) {
    return;
  }

  emittedImageIds.add(artifact.id);
  chunks.push({
    mediaType: defaultGeneratedImageMediaType,
    type: "file",
    url: `data:${defaultGeneratedImageMediaType};base64,${artifact.result}`,
  });
}

export function getOpenAiAgentsSdkDemoArtifactChunks({
  newItems = [],
  rawResponses = [],
}: {
  newItems?: RunItem[];
  rawResponses?: ModelResponse[];
}): UIMessageChunk[] {
  const emittedImageIds = new Set<string>();
  const chunks: UIMessageChunk[] = [];

  for (const item of newItems) {
    appendArtifactChunk(
      chunks,
      emittedImageIds,
      getImageGenerationArtifact({
        output:
          "output" in item && typeof item.output === "string"
            ? item.output
            : undefined,
        rawItem: item.rawItem as ImageGenerationArtifactSource | undefined,
      })
    );
  }

  for (const response of rawResponses) {
    for (const item of response.output) {
      appendArtifactChunk(
        chunks,
        emittedImageIds,
        getImageGenerationArtifact({
          rawItem: item as ImageGenerationArtifactSource,
        })
      );
    }
  }

  return chunks;
}

import type { RunStreamEvent } from "@openai/agents";

import type { OpenAiAgentsSdkDemoMessageMetadata } from "../message-metadata";

function pushUnique(target: string[], value: string | undefined, limit = 8) {
  if (!value || target.includes(value)) {
    return;
  }

  if (target.length >= limit) {
    return;
  }

  target.push(value);
}

async function* iterateReadableStream<T>(stream: ReadableStream<T>) {
  const reader = stream.getReader();

  try {
    while (true) {
      const { done, value } = await reader.read();

      if (done) {
        return;
      }

      yield value;
    }
  } finally {
    reader.releaseLock();
  }
}

function getAsyncIterable(
  source: AsyncIterable<RunStreamEvent> | ReadableStream<RunStreamEvent>
) {
  if (Symbol.asyncIterator in source) {
    return source as AsyncIterable<RunStreamEvent>;
  }

  return iterateReadableStream(source as ReadableStream<RunStreamEvent>);
}

export function createOpenAiAgentsSdkDemoStreamSummaryCollector() {
  const summary = {
    agentNames: [] as string[],
    rawModelEventCount: 0,
    rawModelEventTypes: [] as string[],
    rawModelSources: [] as string[],
    runItemEventCount: 0,
    runItemEventNames: [] as string[],
  };

  return {
    observe(event: RunStreamEvent) {
      if (event.type === "agent_updated_stream_event") {
        pushUnique(summary.agentNames, event.agent.name);
        return;
      }

      if (event.type === "raw_model_stream_event") {
        summary.rawModelEventCount += 1;
        pushUnique(summary.rawModelSources, event.source);
        pushUnique(summary.rawModelEventTypes, event.data.type);
        return;
      }

      if (event.type === "run_item_stream_event") {
        summary.runItemEventCount += 1;
        pushUnique(summary.runItemEventNames, event.name);
      }
    },
    toMetadata(): OpenAiAgentsSdkDemoMessageMetadata | undefined {
      const hasEvents =
        summary.rawModelEventCount > 0 ||
        summary.runItemEventCount > 0 ||
        summary.agentNames.length > 0;

      if (!hasEvents) {
        return;
      }

      return {
        streamSummary: summary,
        usedGuideIds: ["streaming"],
      };
    },
  };
}

export function observeOpenAiAgentsSdkDemoStreamEvents(
  source: AsyncIterable<RunStreamEvent> | ReadableStream<RunStreamEvent>,
  onEvent: (event: RunStreamEvent) => void
): AsyncIterable<RunStreamEvent> {
  const events = getAsyncIterable(source);

  return {
    async *[Symbol.asyncIterator]() {
      for await (const event of events) {
        onEvent(event);
        yield event;
      }
    },
  };
}

