export function createOpenAiAgentsSdkDemoTools({
  env = process.env,
  modelProfile,
}: OpenAiAgentsSdkDemoToolOptions) {
  const vectorStoreIds = getOpenAiAgentsSdkDemoVectorStoreIds(env);
  const supportsToolSearch = supportsOpenAiAgentsSdkToolSearch(
    modelProfile.model
  );

  return [
    createBuildResearchBriefTool(),
    createPublishResearchSummaryTool(),
    ...(supportsToolSearch
      ? [createDraftFinancialFollowUpTool(), createBuildRiskWatchlistTool()]
      : []),
    webSearchTool({
      searchContextSize: "medium",
    }),
    ...(vectorStoreIds.length > 0
      ? [
          fileSearchTool(vectorStoreIds, {
            includeSearchResults: true,
            maxNumResults: 3,
          }),
        ]
      : []),
    codeInterpreterTool({
      includeOutputs: true,
    }),
    imageGenerationTool({
      size: "1024x1024",
    }),
    ...(supportsToolSearch ? [toolSearchTool()] : []),
    createResearchMemoAgentTool({
      modelProfile,
    }),
    createSandboxWorkspaceAgentTool({
      modelProfile,
    }),
  ];
}

export function getOpenAiAgentsSdkDemoToolCatalog({
  env = process.env,
  isChatAvailable,
}: OpenAiAgentsSdkDemoToolCatalogOptions): OpenAiAgentsSdkDemoToolCatalogEntry[] {
  const modelProfile = getOpenAiAgentsSdkDemoModelProfile(env);
  const supportsToolSearch = supportsOpenAiAgentsSdkToolSearch(
    getOpenAiAgentsSdkDemoChatModel(env)
  );
  const hasFileSearchSetup =
    getOpenAiAgentsSdkDemoVectorStoreIds(env).length > 0 && isChatAvailable;
  const isImageGenerationProviderBlocked =
    isOpenAiAgentsSdkDemoImageGenerationProviderBlocked(modelProfile) &&
    isChatAvailable;
  const functionToolContinuationNote =
    modelProfile.baseUrl.includes("ai-gateway.vercel.sh") && isChatAvailable
      ? " The current AI Gateway path can reject the SDK's default run_llm_again continuation after local function tools; the demo surfaces that provider error instead of injecting a fake final answer."
      : "";
  const availability: OpenAiAgentsSdkDemoToolAvailability = isChatAvailable
    ? "configured"
    : "setup-required";
  const deferredToolAvailability: OpenAiAgentsSdkDemoToolAvailability =
    supportsToolSearch && isChatAvailable ? "configured" : "setup-required";

  return [
    {
      availability,
      kind: "function",
      name: "build_research_brief",
      notes: `Thin official tool() example for the Tesla-style research flow.${functionToolContinuationNote}`,
      sdkPrimitive: "tool()",
    },
    {
      availability,
      kind: "function",
      name: "publish_research_summary",
      notes: `Official tool({ needsApproval: true }) path for a human approval interruption before sharing research externally.${functionToolContinuationNote}`,
      sdkPrimitive: "tool({ needsApproval: true })",
    },
    {
      availability: deferredToolAvailability,
      kind: "function",
      name: "draft_financial_follow_up",
      notes: supportsToolSearch
        ? "Deferred top-level function tool loaded on demand through the official tool search flow."
        : "Requires an OpenAI Responses model with tool_search support, such as openai/gpt-5.4-mini or newer.",
      sdkPrimitive: "tool({ deferLoading: true })",
    },
    {
      availability: deferredToolAvailability,
      kind: "function",
      name: "build_risk_watchlist",
      notes: supportsToolSearch
        ? "Deferred top-level function tool loaded on demand through the official tool search flow."
        : "Requires an OpenAI Responses model with tool_search support, such as openai/gpt-5.4-mini or newer.",
      sdkPrimitive: "tool({ deferLoading: true })",
    },
    {
      availability,
      kind: "hosted",
      name: "web_search",
      notes:
        "Hosted OpenAI search through the current AI Gateway OpenAI-compatible Responses path.",
      sdkPrimitive: "webSearchTool()",
    },
    {
      availability,
      kind: "hosted",
      name: "code_interpreter",
      notes:
        "Hosted OpenAI code interpreter for math, tables, and quick analysis.",
      sdkPrimitive: "codeInterpreterTool()",
    },
    {
      availability,
      kind: "agent-as-tool",
      name: "research_memo_agent",
      notes:
        "Specialist sub-agent exposed through agent.asTool() for memo synthesis.",
      sdkPrimitive: "agent.asTool()",
    },
    {
      availability,
      kind: "agent-as-tool",
      name: "sandbox_workspace_agent",
      notes:
        "Official SandboxAgent specialist mounted over the demo docs and feature slice, then exposed through agent.asTool().",
      sdkPrimitive: "SandboxAgent.asTool()",
    },
    {
      availability: hasFileSearchSetup ? "configured" : "setup-required",
      kind: "hosted",
      name: "file_search",
      notes: hasFileSearchSetup
        ? "Official hosted file search backed by OPENAI_AGENTS_VECTOR_STORE_IDS."
        : "Set OPENAI_AGENTS_VECTOR_STORE_IDS to one or more comma-separated OpenAI vector store ids.",
      sdkPrimitive: "fileSearchTool()",
    },
    {
      availability: isImageGenerationProviderBlocked
        ? "provider-blocked"
        : availability,
      kind: "hosted",
      name: "image_generation",
      notes: isImageGenerationProviderBlocked
        ? "Registered through imageGenerationTool(), but blocked on the current AI Gateway Responses path. The hosted image tool can complete without a renderable image artifact, and streamed runs can terminate before the AI SDK UI bridge receives a usable file part."
        : "Official hosted image generation with assistant file output rendered in the current chat surface.",
      sdkPrimitive: "imageGenerationTool()",
    },
    {
      availability: deferredToolAvailability,
      kind: "hosted",
      name: "tool_search",
      notes: supportsToolSearch
        ? "Official hosted tool search for loading deferred namespace members on demand."
        : "Requires an OpenAI Responses model with tool_search support, such as openai/gpt-5.4-mini or newer.",
      sdkPrimitive: "toolSearchTool()",
    },
  ];
}

function getToolName(rawItem: { name?: string; type?: string }): string | null {
  if (
    rawItem.type === "function_call" ||
    rawItem.type === "function_call_result" ||
    rawItem.type === "hosted_tool_call"
  ) {
    if (!rawItem.name) {
      return null;
    }

    if (rawItem.type === "hosted_tool_call" && rawItem.name.endsWith("_call")) {
      return rawItem.name.slice(0, -"_call".length);
    }

    return rawItem.name;
  }

  if (
    rawItem.type === "tool_search_call" ||
    rawItem.type === "tool_search_output"
  ) {
    return "tool_search";
  }

  if (rawItem.type === "image_generation_call") {
    return "image_generation";
  }

  return null;
}

export function getOpenAiAgentsSdkDemoRunUsageMetadata(
  newItems: RunItem[]
): OpenAiAgentsSdkDemoMessageMetadata | undefined {
  const usedToolNames = Array.from(
    new Set(
      newItems
        .map((item) =>
          getToolName((item.rawItem ?? {}) as { name?: string; type?: string })
        )
        .filter((value): value is string => Boolean(value))
    )
  );

  if (usedToolNames.length === 0) {
    return;
  }

  const usedGuideIds = ["tools"];

  if (usedToolNames.includes("research_memo_agent")) {
    usedGuideIds.push("agent-orchestration");
  }

  if (usedToolNames.some((name) => isOpenAiAgentsSdkDemoMcpToolName(name))) {
    usedGuideIds.push("mcp");
  }

  return {
    usedGuideIds,
    usedToolNames,
  };
}

import { generateTraceId } from "@openai/agents";
import type { UIMessage } from "ai";
import { z } from "zod";

import type { OpenAiAgentsSdkDemoMessageMetadata } from "../message-metadata";

type DemoEnv = Record<string, string | undefined>;

const traceDisableEnvVar = "OPENAI_AGENTS_DISABLE_TRACING";
const traceSensitiveDataEnvVar = "OPENAI_AGENTS_TRACE_INCLUDE_SENSITIVE_DATA";
const traceApiKeyEnvVar = "OPENAI_AGENTS_TRACING_API_KEY";
const openAiApiKeyEnvVar = "OPENAI_API_KEY";

export const openAiAgentsSdkDemoTraceSummarySchema = z.object({
  exportApiKeySource: z.enum([
    "OPENAI_AGENTS_TRACING_API_KEY",
    "OPENAI_API_KEY",
    "missing",
  ]),
  groupId: z.string().optional(),
  metadataKeys: z.array(z.string()),
  traceId: z.string(),
  traceIncludeSensitiveData: z.boolean(),
  tracingDisabled: z.boolean(),
  workflowName: z.string(),
});

export interface OpenAiAgentsSdkDemoTraceProfile {
  defaultServerRuntimeTracing: "enabled";
  disableEnvVar: typeof traceDisableEnvVar;
  exportApiKeySource:
    | "OPENAI_AGENTS_TRACING_API_KEY"
    | "OPENAI_API_KEY"
    | "missing";
  groupingStrategy: "session-id";
  sdkPrimitives: [
    "generateTraceId",
    "run({ workflowName, traceId, groupId, traceMetadata, tracingDisabled, traceIncludeSensitiveData, tracing })",
  ];
  traceIncludeSensitiveData: boolean;
  tracingDisabled: boolean;
  usesPerRunExportOverride: true;
  workflowNameSource: "RunConfig.workflowName";
}

function getTracingExportApiKeySource(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoTraceProfile["exportApiKeySource"] {
  if (env[traceApiKeyEnvVar]) {
    return traceApiKeyEnvVar;
  }

  if (env[openAiApiKeyEnvVar]) {
    return openAiApiKeyEnvVar;
  }

  return "missing";
}

function getTracingExportApiKey(env: DemoEnv = process.env) {
  return env[traceApiKeyEnvVar] ?? env[openAiApiKeyEnvVar] ?? undefined;
}

function isTracingDisabled(env: DemoEnv = process.env) {
  return env[traceDisableEnvVar] === "1";
}

function shouldIncludeSensitiveData(env: DemoEnv = process.env) {
  return env[traceSensitiveDataEnvVar] !== "0";
}

function getLatestAssistantTraceSummary(messages: UIMessage[]) {
  return (
    [...messages].reverse().find((message) => message.role === "assistant")
      ?.metadata as OpenAiAgentsSdkDemoMessageMetadata | undefined
  )?.traceSummary;
}

export function getOpenAiAgentsSdkDemoTraceProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoTraceProfile {
  return {
    defaultServerRuntimeTracing: "enabled",
    disableEnvVar: traceDisableEnvVar,
    exportApiKeySource: getTracingExportApiKeySource(env),
    groupingStrategy: "session-id",
    sdkPrimitives: [
      "generateTraceId",
      "run({ workflowName, traceId, groupId, traceMetadata, tracingDisabled, traceIncludeSensitiveData, tracing })",
    ],
    traceIncludeSensitiveData: shouldIncludeSensitiveData(env),
    tracingDisabled: isTracingDisabled(env),
    usesPerRunExportOverride: true,
    workflowNameSource: "RunConfig.workflowName",
  };
}

export function createOpenAiAgentsSdkDemoTraceRunConfig({
  env = process.env,
  sessionId,
  workflowName,
}: {
  env?: DemoEnv;
  sessionId?: string;
  workflowName: string;
}) {
  const exportApiKey = getTracingExportApiKey(env);
  const summary = {
    exportApiKeySource: getTracingExportApiKeySource(env),
    ...(sessionId ? { groupId: sessionId } : {}),
    metadataKeys: ["demo", "session_id"],
    traceId: generateTraceId(),
    traceIncludeSensitiveData: shouldIncludeSensitiveData(env),
    tracingDisabled: isTracingDisabled(env),
    workflowName,
  } satisfies z.infer<typeof openAiAgentsSdkDemoTraceSummarySchema>;

  return {
    options: {
      ...(sessionId ? { groupId: sessionId } : {}),
      traceId: summary.traceId,
      traceIncludeSensitiveData: summary.traceIncludeSensitiveData,
      traceMetadata: {
        demo: "openai-agents-sdk-demo",
        session_id: sessionId ?? "unknown",
      },
      tracingDisabled: summary.tracingDisabled,
      ...(exportApiKey ? { tracing: { apiKey: exportApiKey } } : {}),
      workflowName: summary.workflowName,
    },
    summary,
  };
}

export function getOpenAiAgentsSdkDemoTraceUsageMetadata(
  summary: z.infer<typeof openAiAgentsSdkDemoTraceSummarySchema> | undefined
) {
  if (!summary) {
    return;
  }

  return {
    traceSummary: summary,
    usedGuideIds: ["tracing"],
  } satisfies OpenAiAgentsSdkDemoMessageMetadata;
}

export function getOpenAiAgentsSdkDemoLatestTraceUsageMetadata(
  messages: UIMessage[]
) {
  return getOpenAiAgentsSdkDemoTraceUsageMetadata(
    getLatestAssistantTraceSummary(messages)
  );
}

import {
  createOpenAiAgentsSdkDemoCloudflareWorkerRuntime,
  type OpenAiAgentsSdkDemoCloudflareWorkerRuntime,
} from "./voice-cloudflare-worker";

type DemoEnv = Record<string, string | undefined>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY" as const;
const cloudflareWorkflowName =
  "openai-agents-sdk-demo-voice-cloudflare" as const;
const cloudflareRootRoutePath = "/" as const;
const cloudflareConnectRoutePath = "/connect" as const;
const cloudflareHealthcheckMessage =
  "Cloudflare Realtime Worker is running!" as const;

export interface OpenAiAgentsSdkDemoCloudflareWorkerAppProfile {
  connectRoutePath: typeof cloudflareConnectRoutePath;
  healthcheckMessage: typeof cloudflareHealthcheckMessage;
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  publicTransportContract: "deployed-worker-fetch-handler";
  rootRoutePath: typeof cloudflareRootRoutePath;
  sdkPrimitive: "CloudflareRealtimeTransportLayer + RealtimeSession";
  serverPrimitive: "export default { fetch(request, env, ctx) }";
  sourceGuide: "https://openai.github.io/openai-agents-js/extensions/cloudflare/";
  status: "configured" | "setup-required";
  websocketUpgradePrimitive: "fetch() + Upgrade: websocket";
  workerCompatibilityFlag: "nodejs_compat";
  workflowName: typeof cloudflareWorkflowName;
}

export interface OpenAiAgentsSdkDemoCloudflareWorkerApp {
  handleRequest: (request: Request) => Promise<Response>;
  profile: OpenAiAgentsSdkDemoCloudflareWorkerAppProfile;
}

interface OpenAiAgentsSdkDemoCloudflareWorkerAppDependencies {
  createRuntime?: (env?: DemoEnv) => OpenAiAgentsSdkDemoCloudflareWorkerRuntime;
}

function buildUpgradeRequiredResponse() {
  return Response.json(
    {
      error:
        "Cloudflare worker connect route requires Upgrade: websocket so the deployed runtime matches the official workerd transport contract.",
    },
    { status: 426 }
  );
}

function isWebSocketUpgrade(request: Request) {
  return request.headers.get("upgrade")?.toLowerCase() === "websocket";
}

export function getOpenAiAgentsSdkDemoCloudflareWorkerAppProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoCloudflareWorkerAppProfile {
  return {
    connectRoutePath: cloudflareConnectRoutePath,
    healthcheckMessage: cloudflareHealthcheckMessage,
    openAiApiKeyEnvVar,
    publicTransportContract: "deployed-worker-fetch-handler",
    rootRoutePath: cloudflareRootRoutePath,
    sdkPrimitive: "CloudflareRealtimeTransportLayer + RealtimeSession",
    serverPrimitive: "export default { fetch(request, env, ctx) }",
    sourceGuide:
      "https://openai.github.io/openai-agents-js/extensions/cloudflare/",
    status: env[openAiApiKeyEnvVar] ? "configured" : "setup-required",
    websocketUpgradePrimitive: "fetch() + Upgrade: websocket",
    workerCompatibilityFlag: "nodejs_compat",
    workflowName: cloudflareWorkflowName,
  };
}

export function createOpenAiAgentsSdkDemoCloudflareWorkerApp(
  env: DemoEnv = process.env,
  dependencies: OpenAiAgentsSdkDemoCloudflareWorkerAppDependencies = {}
): OpenAiAgentsSdkDemoCloudflareWorkerApp {
  const createRuntime =
    dependencies.createRuntime ??
    ((environment: DemoEnv) =>
      createOpenAiAgentsSdkDemoCloudflareWorkerRuntime(environment));

  return {
    handleRequest: async (request) => {
      const pathname = new URL(request.url).pathname;

      if (pathname === cloudflareRootRoutePath) {
        return Response.json({
          message: cloudflareHealthcheckMessage,
        });
      }

      if (pathname !== cloudflareConnectRoutePath) {
        return new Response("Not Found", { status: 404 });
      }

      if (!isWebSocketUpgrade(request)) {
        return buildUpgradeRequiredResponse();
      }

      const runtime = createRuntime(env);

      await runtime.connect();

      try {
        return Response.json({
          state: runtime.getState(),
          transportName: runtime.transportName,
          workflowName: runtime.profile.workflowName,
        });
      } finally {
        runtime.close();
      }
    },
    profile: getOpenAiAgentsSdkDemoCloudflareWorkerAppProfile(env),
  };
}

