const openAiApiKeyEnvVar = "OPENAI_API_KEY" as const;
const cloudflareWorkflowName =
  "openai-agents-sdk-demo-voice-cloudflare" as const;

type CloudflareSessionLike = Pick<RealtimeSession, "close" | "connect">;

export interface OpenAiAgentsSdkDemoCloudflareWorkerProfile {
  connectPrimitive: "RealtimeSession.connect({ apiKey, model })";
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  openEventBehavior: "skipOpenEventListeners: true";
  runtimeEntryPoint: "Cloudflare Worker fetch()";
  sdkPrimitive: "CloudflareRealtimeTransportLayer + RealtimeSession";
  sourceGuide: "https://openai.github.io/openai-agents-js/extensions/cloudflare/";
  status: "configured" | "setup-required";
  transport: "WebSocket";
  websocketUpgradePrimitive: "fetch() + Upgrade: websocket";
  workerCompatibilityFlag: "nodejs_compat";
  workflowName: typeof cloudflareWorkflowName;
}

export interface OpenAiAgentsSdkDemoCloudflareWorkerState {
  closeCount: number;
  connectCount: number;
  isConnected: boolean;
}

export interface OpenAiAgentsSdkDemoCloudflareWorkerRuntime {
  close: () => void;
  connect: () => Promise<void>;
  getState: () => OpenAiAgentsSdkDemoCloudflareWorkerState;
  profile: OpenAiAgentsSdkDemoCloudflareWorkerProfile;
  session: CloudflareSessionLike;
  transportName: string;
}

interface OpenAiAgentsSdkDemoCloudflareWorkerDependencies {
  buildSessionHandle?: (env?: DemoEnv) =>
    | OpenAiAgentsSdkDemoVoiceExtensionHandle<any>
    | {
        connectOptions: {
          apiKey: string;
          model: string;
        };
        profile: {
          status: "configured" | "setup-required";
        };
        session: CloudflareSessionLike;
        transport: {
          constructor: {
            name: string;
          };
        };
      };
}

export function getOpenAiAgentsSdkDemoCloudflareWorkerProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoCloudflareWorkerProfile {
  return {
    connectPrimitive: "RealtimeSession.connect({ apiKey, model })",
    openAiApiKeyEnvVar,
    openEventBehavior: "skipOpenEventListeners: true",
    runtimeEntryPoint: "Cloudflare Worker fetch()",
    sdkPrimitive: "CloudflareRealtimeTransportLayer + RealtimeSession",
    sourceGuide:
      "https://openai.github.io/openai-agents-js/extensions/cloudflare/",
    status: env[openAiApiKeyEnvVar] ? "configured" : "setup-required",
    transport: "WebSocket",
    websocketUpgradePrimitive: "fetch() + Upgrade: websocket",
    workerCompatibilityFlag: "nodejs_compat",
    workflowName: cloudflareWorkflowName,
  };
}

export function createOpenAiAgentsSdkDemoCloudflareWorkerRuntime(
  env: DemoEnv = process.env,
  dependencies: OpenAiAgentsSdkDemoCloudflareWorkerDependencies = {}
): OpenAiAgentsSdkDemoCloudflareWorkerRuntime {
  const buildSessionHandle =
    dependencies.buildSessionHandle ??
    buildOpenAiAgentsSdkDemoCloudflareVoiceSession;
  const handle = buildSessionHandle(env);
  const state: OpenAiAgentsSdkDemoCloudflareWorkerState = {
    closeCount: 0,
    connectCount: 0,
    isConnected: false,
  };

  return {
    close: () => {
      state.closeCount += 1;
      state.isConnected = false;
      handle.session.close();
    },
    connect: async () => {
      await handle.session.connect(handle.connectOptions);
      state.connectCount += 1;
      state.isConnected = true;
    },
    getState: () => ({
      ...state,
    }),
    profile: getOpenAiAgentsSdkDemoCloudflareWorkerProfile(env),
    session: handle.session,
    transportName: handle.transport.constructor.name,
  };
}

import {
  RealtimeSession,
  type RealtimeSessionConnectOptions,
  type RealtimeTransportLayer,
} from "@openai/agents/realtime";
import {
  CloudflareRealtimeTransportLayer,
  TwilioRealtimeTransportLayer,
} from "@openai/agents-extensions";

import { createOpenAiAgentsSdkDemoVoiceAgentBundle } from "../voice-lane";

type DemoEnv = Record<string, string | undefined>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY" as const;
const defaultVoiceSessionModel = "gpt-realtime-2" as const;
const defaultVoiceSessionVoice = "marin" as const;
const cloudflareWorkflowName =
  "openai-agents-sdk-demo-voice-cloudflare" as const;
const twilioWorkflowName = "openai-agents-sdk-demo-voice-twilio" as const;

export interface OpenAiAgentsSdkDemoVoiceExtensionProfile {
  credentialContract: "server-api-key";
  id: "cloudflare" | "twilio";
  label: "Cloudflare Workers" | "Twilio Media Streams";
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  runtimeContract:
    | "bring-your-own-websocket-server"
    | "cloudflare-worker-runtime";
  sdkPrimitive:
    | "CloudflareRealtimeTransportLayer"
    | "TwilioRealtimeTransportLayer";
  sourceGuide: string;
  status: "configured" | "setup-required";
  transport: "WebSocket";
  workflowName: typeof cloudflareWorkflowName | typeof twilioWorkflowName;
}

export interface OpenAiAgentsSdkDemoVoiceExtensionHandle<
  TTransport extends
    | CloudflareRealtimeTransportLayer
    | TwilioRealtimeTransportLayer,
> {
  connectOptions: RealtimeSessionConnectOptions;
  profile: OpenAiAgentsSdkDemoVoiceExtensionProfile;
  session: RealtimeSession;
  transport: TTransport;
}

type TwilioTransportSocket = ConstructorParameters<
  typeof TwilioRealtimeTransportLayer
>[0]["twilioWebSocket"];

function getRequiredOpenAiApiKey(env: DemoEnv = process.env) {
  const apiKey = env[openAiApiKeyEnvVar];

  if (!apiKey) {
    throw new Error(
      "OPENAI_API_KEY is missing. Provider-specific voice transports require a native OpenAI API key."
    );
  }

  return apiKey;
}

function getVoiceExtensionProfileStatus(env: DemoEnv = process.env) {
  return env[openAiApiKeyEnvVar] ? "configured" : "setup-required";
}

function getOpenAiAgentsSdkDemoCloudflareVoiceExtensionProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoVoiceExtensionProfile {
  return {
    credentialContract: "server-api-key",
    id: "cloudflare",
    label: "Cloudflare Workers",
    openAiApiKeyEnvVar,
    runtimeContract: "cloudflare-worker-runtime",
    sdkPrimitive: "CloudflareRealtimeTransportLayer",
    sourceGuide:
      "https://openai.github.io/openai-agents-js/extensions/cloudflare/",
    status: getVoiceExtensionProfileStatus(env),
    transport: "WebSocket",
    workflowName: cloudflareWorkflowName,
  };
}

function getOpenAiAgentsSdkDemoTwilioVoiceExtensionProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoVoiceExtensionProfile {
  return {
    credentialContract: "server-api-key",
    id: "twilio",
    label: "Twilio Media Streams",
    openAiApiKeyEnvVar,
    runtimeContract: "bring-your-own-websocket-server",
    sdkPrimitive: "TwilioRealtimeTransportLayer",
    sourceGuide: "https://openai.github.io/openai-agents-js/extensions/twilio/",
    status: getVoiceExtensionProfileStatus(env),
    transport: "WebSocket",
    workflowName: twilioWorkflowName,
  };
}

function createOpenAiAgentsSdkDemoVoiceSession({
  transport,
  workflowName,
}: {
  transport: RealtimeTransportLayer;
  workflowName: typeof cloudflareWorkflowName | typeof twilioWorkflowName;
}) {
  const { primaryAgent } = createOpenAiAgentsSdkDemoVoiceAgentBundle();

  return new RealtimeSession(primaryAgent, {
    config: {
      audio: {
        output: {
          voice: defaultVoiceSessionVoice,
        },
      },
    },
    model: defaultVoiceSessionModel,
    transport,
    workflowName,
  });
}

export function getOpenAiAgentsSdkDemoVoiceExtensionProfiles(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoVoiceExtensionProfile[] {
  return [
    getOpenAiAgentsSdkDemoCloudflareVoiceExtensionProfile(env),
    getOpenAiAgentsSdkDemoTwilioVoiceExtensionProfile(env),
  ];
}

export function buildOpenAiAgentsSdkDemoCloudflareVoiceSession(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoVoiceExtensionHandle<CloudflareRealtimeTransportLayer> {
  const apiKey = getRequiredOpenAiApiKey(env);
  const profile = getOpenAiAgentsSdkDemoCloudflareVoiceExtensionProfile(env);
  const transport = new CloudflareRealtimeTransportLayer({
    useInsecureApiKey: true,
  });
  const session = createOpenAiAgentsSdkDemoVoiceSession({
    transport,
    workflowName: cloudflareWorkflowName,
  });

  return {
    connectOptions: {
      apiKey,
      model: defaultVoiceSessionModel,
    },
    profile,
    session,
    transport,
  };
}

export function buildOpenAiAgentsSdkDemoTwilioVoiceSession({
  env = process.env,
  twilioWebSocket,
}: {
  env?: DemoEnv;
  twilioWebSocket: TwilioTransportSocket;
}): OpenAiAgentsSdkDemoVoiceExtensionHandle<TwilioRealtimeTransportLayer> {
  const apiKey = getRequiredOpenAiApiKey(env);
  const profile = getOpenAiAgentsSdkDemoTwilioVoiceExtensionProfile(env);
  const transport = new TwilioRealtimeTransportLayer({
    twilioWebSocket,
    useInsecureApiKey: true,
  });
  const session = createOpenAiAgentsSdkDemoVoiceSession({
    transport,
    workflowName: twilioWorkflowName,
  });

  return {
    connectOptions: {
      apiKey,
      model: defaultVoiceSessionModel,
    },
    profile,
    session,
    transport,
  };
}

import { createHash } from "node:crypto";

import OpenAI from "openai";
import type { ClientSecretCreateResponse } from "openai/resources/realtime";
import { z } from "zod";

type DemoEnv = Record<string, string | undefined>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY";
const voiceClientSecretRoutePath =
  "/api/demos/openai-agents-sdk-demo/realtime/client-secrets" as const;
const defaultVoiceSessionModel = "gpt-realtime-2" as const;
const defaultVoiceSessionVoice = "marin" as const;
const defaultVoiceClientSecretTtlSeconds = 600 as const;
const invalidRequestBodyError =
  'Expected a JSON body with an optional "sessionId" string.';

const voiceClientSecretRequestBodySchema = z.object({
  sessionId: z.string().trim().min(1).max(200).optional(),
});

interface OpenAiAgentsSdkDemoVoiceClientSecretRequestBody {
  sessionId?: string;
}

export interface OpenAiAgentsSdkDemoVoiceClientSecretRouteState {
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  routePath: typeof voiceClientSecretRoutePath;
  sdkPrimitive: "client.realtime.clientSecrets.create()";
  sessionModel: typeof defaultVoiceSessionModel;
  sessionVoice: typeof defaultVoiceSessionVoice;
  status: "configured" | "setup-required";
}

export type OpenAiAgentsSdkDemoVoiceClientSecretResponse =
  ClientSecretCreateResponse;

interface OpenAiAgentsSdkDemoVoiceClientSecretDependencies {
  createClientSecret: (options: {
    apiKey: string;
    params: {
      expires_after: {
        anchor: "created_at";
        seconds: typeof defaultVoiceClientSecretTtlSeconds;
      };
      session: {
        audio: {
          output: {
            voice: typeof defaultVoiceSessionVoice;
          };
        };
        model: typeof defaultVoiceSessionModel;
        type: "realtime";
      };
    };
    safetyIdentifier: string;
  }) => Promise<OpenAiAgentsSdkDemoVoiceClientSecretResponse>;
}

function getRequiredOpenAiApiKey(env: DemoEnv = process.env) {
  const apiKey = env[openAiApiKeyEnvVar];

  if (!apiKey) {
    throw new Error(
      "OPENAI_API_KEY is missing. Voice Agents client-secret minting requires a native OpenAI API key; AI Gateway keys do not work for this realtime route."
    );
  }

  return apiKey;
}

function getOpenAiAgentsSdkDemoVoiceClientSecretParams() {
  return {
    expires_after: {
      anchor: "created_at" as const,
      seconds: defaultVoiceClientSecretTtlSeconds,
    },
    session: {
      audio: {
        output: {
          voice: defaultVoiceSessionVoice,
        },
      },
      model: defaultVoiceSessionModel,
      type: "realtime" as const,
    },
  };
}

function getOpenAiAgentsSdkDemoVoiceSafetyIdentifier(sessionId?: string) {
  return createHash("sha256")
    .update(`openai-agents-sdk-demo:${sessionId ?? "anonymous"}`)
    .digest("hex");
}

async function createOpenAiAgentsSdkDemoVoiceClientSecret({
  apiKey,
  params,
  safetyIdentifier,
}: Parameters<
  OpenAiAgentsSdkDemoVoiceClientSecretDependencies["createClientSecret"]
>[0]): Promise<OpenAiAgentsSdkDemoVoiceClientSecretResponse> {
  const client = new OpenAI({
    apiKey,
  });

  const response = await client.realtime.clientSecrets.create(params, {
    headers: {
      "OpenAI-Safety-Identifier": safetyIdentifier,
    },
  });

  return response;
}

async function readOpenAiAgentsSdkDemoVoiceClientSecretBody(request: Request) {
  const bodyText = await request.text();

  if (!bodyText.trim()) {
    return {} satisfies OpenAiAgentsSdkDemoVoiceClientSecretRequestBody;
  }

  try {
    return voiceClientSecretRequestBodySchema.parse(JSON.parse(bodyText));
  } catch {
    throw new Error(invalidRequestBodyError);
  }
}

export function getOpenAiAgentsSdkDemoVoiceClientSecretRouteState(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoVoiceClientSecretRouteState {
  return {
    openAiApiKeyEnvVar,
    routePath: voiceClientSecretRoutePath,
    sdkPrimitive: "client.realtime.clientSecrets.create()",
    sessionModel: defaultVoiceSessionModel,
    sessionVoice: defaultVoiceSessionVoice,
    status: env[openAiApiKeyEnvVar] ? "configured" : "setup-required",
  };
}

export async function handleOpenAiAgentsSdkDemoVoiceClientSecretRequest(
  request: Request,
  env: DemoEnv = process.env,
  dependencies: OpenAiAgentsSdkDemoVoiceClientSecretDependencies = {
    createClientSecret: createOpenAiAgentsSdkDemoVoiceClientSecret,
  }
) {
  try {
    const body = await readOpenAiAgentsSdkDemoVoiceClientSecretBody(request);
    const params = getOpenAiAgentsSdkDemoVoiceClientSecretParams();
    const response = await dependencies.createClientSecret({
      apiKey: getRequiredOpenAiApiKey(env),
      params,
      safetyIdentifier: getOpenAiAgentsSdkDemoVoiceSafetyIdentifier(
        body.sessionId
      ),
    });

    return Response.json(response);
  } catch (error) {
    const message =
      error instanceof Error ? error.message : "Failed to mint client secret.";
    const status = message === invalidRequestBodyError ? 400 : 500;

    return Response.json(
      {
        error: message,
      },
      { status }
    );
  }
}

import type {
  RealtimeSession,
  RealtimeSessionConnectOptions,
  TransportEvent,
  TransportLayerAudio,
} from "@openai/agents/realtime";

import {
  buildOpenAiAgentsSdkDemoServerVoiceSession,
  type OpenAiAgentsSdkDemoServerVoiceSessionHandle,
} from "./voice-websocket";

type DemoEnv = Record<string, string | undefined>;

type VoiceSessionLike = Pick<
  RealtimeSession,
  "close" | "connect" | "interrupt" | "mute" | "on" | "sendAudio" | "transport"
>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY" as const;
const defaultVoiceSessionModel = "gpt-realtime-2" as const;
const defaultVoiceSessionVoice = "marin" as const;
const defaultVoiceWorkflowName =
  "openai-agents-sdk-demo-voice-websocket" as const;

export interface OpenAiAgentsSdkDemoServerAudioLaneProfile {
  inputPrimitive: "RealtimeSession.sendAudio()";
  interruptPrimitive: "RealtimeSession.interrupt()";
  model: typeof defaultVoiceSessionModel;
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  outputAudioEvent: "session.on('audio')";
  outputTranscriptEvent: "session.on('transport_event')";
  requestResponsePrimitive: "session.transport.requestResponse()";
  sessionVoice: typeof defaultVoiceSessionVoice;
  sourceGuide: "https://openai.github.io/openai-agents-js/guides/voice-agents/transport/";
  status: "configured" | "setup-required";
  transport: "WebSocket";
  workflowName: typeof defaultVoiceWorkflowName;
}

export interface OpenAiAgentsSdkDemoServerAudioLaneState {
  interruptionCount: number;
  isOutputActive: boolean;
  outputAudioChunkCount: number;
  transportEventCount: number;
}

export interface OpenAiAgentsSdkDemoServerAudioLane {
  close: () => void;
  connect: () => Promise<void>;
  getState: () => OpenAiAgentsSdkDemoServerAudioLaneState;
  interrupt: () => void;
  mute: (muted: boolean) => void;
  profile: OpenAiAgentsSdkDemoServerAudioLaneProfile;
  requestResponse: (response?: Record<string, unknown>) => void;
  sendAudio: (audio: ArrayBuffer, options?: { commit?: boolean }) => void;
  session: VoiceSessionLike;
  takeOutputAudio: () => TransportLayerAudio[];
  takeTransportEvents: () => TransportEvent[];
}

interface OpenAiAgentsSdkDemoServerAudioLaneDependencies {
  buildSessionHandle?: (env: DemoEnv) =>
    | OpenAiAgentsSdkDemoServerVoiceSessionHandle
    | {
        connectOptions: RealtimeSessionConnectOptions;
        profile: OpenAiAgentsSdkDemoServerVoiceSessionHandle["profile"];
        session: VoiceSessionLike;
      };
}

function cloneAudioEvent(event: TransportLayerAudio): TransportLayerAudio {
  return {
    data: event.data.slice(0),
    responseId: event.responseId,
    type: event.type,
  };
}

export function getOpenAiAgentsSdkDemoServerAudioLaneProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoServerAudioLaneProfile {
  return {
    inputPrimitive: "RealtimeSession.sendAudio()",
    interruptPrimitive: "RealtimeSession.interrupt()",
    model: defaultVoiceSessionModel,
    openAiApiKeyEnvVar,
    outputAudioEvent: "session.on('audio')",
    outputTranscriptEvent: "session.on('transport_event')",
    requestResponsePrimitive: "session.transport.requestResponse()",
    sessionVoice: defaultVoiceSessionVoice,
    sourceGuide:
      "https://openai.github.io/openai-agents-js/guides/voice-agents/transport/",
    status: env[openAiApiKeyEnvVar] ? "configured" : "setup-required",
    transport: "WebSocket",
    workflowName: defaultVoiceWorkflowName,
  };
}

export function buildOpenAiAgentsSdkDemoServerAudioLane(
  env: DemoEnv = process.env,
  dependencies: OpenAiAgentsSdkDemoServerAudioLaneDependencies = {}
): OpenAiAgentsSdkDemoServerAudioLane {
  const buildSessionHandle =
    dependencies.buildSessionHandle ??
    buildOpenAiAgentsSdkDemoServerVoiceSession;
  const handle = buildSessionHandle(env);
  const outputAudio: TransportLayerAudio[] = [];
  const transportEvents: TransportEvent[] = [];
  const state: OpenAiAgentsSdkDemoServerAudioLaneState = {
    interruptionCount: 0,
    isOutputActive: false,
    outputAudioChunkCount: 0,
    transportEventCount: 0,
  };

  handle.session.on("audio", (event: TransportLayerAudio) => {
    outputAudio.push(cloneAudioEvent(event));
    state.outputAudioChunkCount += 1;
  });
  handle.session.on("transport_event", (event: TransportEvent) => {
    transportEvents.push(event);
    state.transportEventCount += 1;
  });
  handle.session.on("audio_start", () => {
    state.isOutputActive = true;
  });
  handle.session.on("audio_stopped", () => {
    state.isOutputActive = false;
  });
  handle.session.on("audio_interrupted", () => {
    state.interruptionCount += 1;
    state.isOutputActive = false;
  });

  return {
    close: () => {
      handle.session.close();
    },
    connect: async () => {
      await handle.session.connect(handle.connectOptions);
    },
    getState: () => ({
      ...state,
    }),
    interrupt: () => {
      handle.session.interrupt();
    },
    mute: (muted: boolean) => {
      handle.session.mute(muted);
    },
    profile: getOpenAiAgentsSdkDemoServerAudioLaneProfile(env),
    requestResponse: (response) => {
      const requestResponse = handle.session.transport.requestResponse;

      if (typeof requestResponse !== "function") {
        throw new Error(
          "The current realtime transport does not expose requestResponse()."
        );
      }

      requestResponse(response);
    },
    sendAudio: (audio, options) => {
      handle.session.sendAudio(audio, options);
    },
    session: handle.session,
    takeOutputAudio: () => outputAudio.splice(0, outputAudio.length),
    takeTransportEvents: () =>
      transportEvents.splice(0, transportEvents.length),
  };
}

import { z } from "zod";

import { buildOpenAiAgentsSdkDemoSipInitialConfig } from "./voice-sip";

type DemoEnv = Record<string, string | undefined>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY";
const sipRoutePath = "/api/demos/openai-agents-sdk-demo/realtime/sip" as const;
const invalidRequestBodyError =
  'Expected a JSON body with a required "callId" string.';

const sipRequestBodySchema = z.object({
  callId: z.string().trim().min(1).max(200),
});

interface OpenAiAgentsSdkDemoSipRequestBody {
  callId: string;
}

export interface OpenAiAgentsSdkDemoSipRouteState {
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  routePath: typeof sipRoutePath;
  sdkPrimitive: "OpenAIRealtimeSIP.buildInitialConfig()";
  status: "configured" | "setup-required";
}

interface OpenAiAgentsSdkDemoSipRouteDependencies {
  buildInitialConfig: () => Promise<unknown>;
}

function getRequiredOpenAiApiKey(env: DemoEnv = process.env) {
  const apiKey = env[openAiApiKeyEnvVar];

  if (!apiKey) {
    throw new Error(
      "OPENAI_API_KEY is missing. SIP accept-payload generation requires a native OpenAI API key because the downstream realtime call-control lane still depends on it."
    );
  }

  return apiKey;
}

async function readOpenAiAgentsSdkDemoSipBody(request: Request) {
  const bodyText = await request.text();

  if (!bodyText.trim()) {
    throw new Error(invalidRequestBodyError);
  }

  try {
    return sipRequestBodySchema.parse(
      JSON.parse(bodyText)
    ) satisfies OpenAiAgentsSdkDemoSipRequestBody;
  } catch {
    throw new Error(invalidRequestBodyError);
  }
}

export function getOpenAiAgentsSdkDemoSipRouteState(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoSipRouteState {
  return {
    openAiApiKeyEnvVar,
    routePath: sipRoutePath,
    sdkPrimitive: "OpenAIRealtimeSIP.buildInitialConfig()",
    status: env[openAiApiKeyEnvVar] ? "configured" : "setup-required",
  };
}

export async function handleOpenAiAgentsSdkDemoSipRequest(
  request: Request,
  env: DemoEnv = process.env,
  dependencies: OpenAiAgentsSdkDemoSipRouteDependencies = {
    buildInitialConfig: buildOpenAiAgentsSdkDemoSipInitialConfig,
  }
) {
  try {
    getRequiredOpenAiApiKey(env);

    const body = await readOpenAiAgentsSdkDemoSipBody(request);
    const acceptPayload = await dependencies.buildInitialConfig();

    return Response.json({
      acceptPayload,
      callId: body.callId,
    });
  } catch (error) {
    const message =
      error instanceof Error ? error.message : "Failed to build SIP payload.";
    const status = message === invalidRequestBodyError ? 400 : 500;

    return Response.json(
      {
        error: message,
      },
      { status }
    );
  }
}

import {
  OpenAIRealtimeSIP,
  RealtimeSession,
  type RealtimeSessionConnectOptions,
} from "@openai/agents/realtime";

import { createOpenAiAgentsSdkDemoVoiceAgentBundle } from "../voice-lane";

type DemoEnv = Record<string, string | undefined>;

const openAiApiKeyEnvVar = "OPENAI_API_KEY" as const;
const defaultVoiceSessionModel = "gpt-realtime-2" as const;
const defaultVoiceSessionVoice = "marin" as const;
const defaultSipWorkflowName = "openai-agents-sdk-demo-voice-sip" as const;

export interface OpenAiAgentsSdkDemoSipVoiceSessionProfile {
  callControlContract: "provider-or-openai-call-accept-route";
  connectPrimitive: "RealtimeSession.connect({ apiKey, callId })";
  initialConfigPrimitive: "OpenAIRealtimeSIP.buildInitialConfig()";
  model: typeof defaultVoiceSessionModel;
  openAiApiKeyEnvVar: typeof openAiApiKeyEnvVar;
  routePath: "/api/demos/openai-agents-sdk-demo/realtime/sip";
  sessionVoice: typeof defaultVoiceSessionVoice;
  sourceGuide: "https://openai.github.io/openai-agents-js/guides/voice-agents/transport/";
  status: "configured" | "setup-required";
  transport: "SIP";
  workflowName: typeof defaultSipWorkflowName;
}

export interface OpenAiAgentsSdkDemoSipVoiceSessionHandle {
  connectOptions: RealtimeSessionConnectOptions;
  profile: OpenAiAgentsSdkDemoSipVoiceSessionProfile;
  session: RealtimeSession;
  transport: OpenAIRealtimeSIP;
}

function getRequiredOpenAiApiKey(env: DemoEnv = process.env) {
  const apiKey = env[openAiApiKeyEnvVar];

  if (!apiKey) {
    throw new Error(
      "OPENAI_API_KEY is missing. SIP voice transport requires a native OpenAI API key."
    );
  }

  return apiKey;
}

function getRequiredCallId(callId: string) {
  if (callId.trim().length === 0) {
    throw new Error(
      "OpenAIRealtimeSIP requires a non-empty callId from an existing SIP-initiated Realtime call."
    );
  }

  return callId;
}

export function getOpenAiAgentsSdkDemoSipVoiceSessionProfile(
  env: DemoEnv = process.env
): OpenAiAgentsSdkDemoSipVoiceSessionProfile {
  return {
    callControlContract: "provider-or-openai-call-accept-route",
