    env?: DemoEnv;
    twilioWebSocket: TwilioSocket;
  }) =>
    | OpenAiAgentsSdkDemoVoiceExtensionHandle<any>
    | {
        connectOptions: {
          apiKey: string;
          model: string;
        };
        profile: {
          status: "configured" | "setup-required";
        };
